import{_ as e,o,c as r,ag as n}from"./chunks/framework.ePeAWSvT.js";const p=JSON.parse('{"title":"Common Model Definitions","description":"","frontmatter":{},"headers":[],"relativePath":"guide/reference-common-model.md","filePath":"guide/reference-common-model.md"}'),a={name:"guide/reference-common-model.md"};function d(s,t,i,c,l,u){return o(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="common-model-definitions" tabindex="-1">Common Model Definitions <a class="header-anchor" href="#common-model-definitions" aria-label="Permalink to &quot;Common Model Definitions&quot;">​</a></h1><p>The Central Common Model provides a standardized vocabulary of entity types used across all integrations. These definitions ensure consistent data mapping between connected systems, regardless of how each system names or structures its own data. When building <a href="./build-data-models.html">Data Models</a>, your Schema Definitions align to these entity types.</p><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th><th>Example</th></tr></thead><tbody><tr><td><strong>Asset</strong></td><td>A resource owned by the company that has economic value, such as equipment, vehicles, or intellectual property.</td><td>A company car used by the sales team, or a software license purchased for office use.</td></tr><tr><td><strong>BOM Revision</strong></td><td>A version of a Bill of Materials (BOM) that reflects changes or updates to the components required to manufacture a product.</td><td>The latest version of a BOM to include a new type of screw in the assembly of a product.</td></tr><tr><td><strong>Company</strong></td><td>A legal entity or business organization that a company may have a relationship with, such as a supplier, vendor, customer, or partner.</td><td>&quot;ABC Manufacturing Inc.&quot; is a company that is a current customer.</td></tr><tr><td><strong>Expense Entry</strong></td><td>A record of costs incurred by the company, typically entered for reimbursement or accounting purposes.</td><td>A $50 expense entry for office supplies purchased by an employee.</td></tr><tr><td><strong>File</strong></td><td>A digital document or attachment stored within a system, often linked to specific records.</td><td>A PDF of a signed contract uploaded to a vendor&#39;s profile.</td></tr><tr><td><strong>Financial Account</strong></td><td>An account used to record financial transactions, such as bank accounts, cash accounts, or credit card accounts.</td><td>The company&#39;s checking account at a local bank.</td></tr><tr><td><strong>Financial Transaction</strong></td><td>A record of any exchange or transfer of financial value within the company.</td><td>A $500 payment to a supplier for raw materials.</td></tr><tr><td><strong>Inventory Transaction</strong></td><td>A record of movements or changes in inventory levels, such as stock additions or withdrawals.</td><td>Receiving 100 units of a product into the warehouse.</td></tr><tr><td><strong>Invoice</strong></td><td>A document issued to customers or from vendors detailing goods or services provided and the amount owed.</td><td>An invoice sent to a customer for a recent order of 50 products.</td></tr><tr><td><strong>Lead</strong></td><td>A potential customer or client that has shown interest in the company&#39;s products or services.</td><td>A contact form submission from someone interested in your software.</td></tr><tr><td><strong>Opportunity</strong></td><td>A potential sales deal or business venture that the company is pursuing.</td><td>A negotiation with a prospective client to close a deal worth $100,000.</td></tr><tr><td><strong>Organizational Unit</strong></td><td>A subdivision of the company, such as a department or team, that performs specific functions.</td><td>The Marketing Department or the Sales Team.</td></tr><tr><td><strong>Package</strong></td><td>A grouping of items or components that are shipped or handled together.</td><td>A package containing 5 different products shipped to a customer.</td></tr><tr><td><strong>Person</strong></td><td>An individual associated with the company, or with a customer or vendor of the company, such as an employee, contractor, or contact.</td><td>John Doe, a sales representative at the company.</td></tr><tr><td><strong>Product</strong></td><td>An item or service offered by the company for sale to customers.</td><td>A new laptop model available for purchase.</td></tr><tr><td><strong>Production Planning Schedule</strong></td><td>A timeline or plan outlining when and how products will be manufactured.</td><td>A weekly schedule detailing the production of 500 units of a specific product.</td></tr><tr><td><strong>Project</strong></td><td>A temporary endeavor undertaken by the company to create a unique product, service, or result.</td><td>A project to develop a new software module for a client.</td></tr><tr><td><strong>Purchase Order</strong></td><td>A document issued by the company to a supplier, requesting the purchase of goods or services.</td><td>A purchase order for 200 units of raw materials.</td></tr><tr><td><strong>Sales Order</strong></td><td>A document confirming a customer&#39;s order for products or services.</td><td>A sales order for 100 units of a product placed by a customer.</td></tr><tr><td><strong>Shipment</strong></td><td>The process or record of sending goods from the company to a customer or another location.</td><td>A shipment of products sent to a retailer.</td></tr><tr><td><strong>Time Entry</strong></td><td>A record of hours worked by an employee or contractor, often used for payroll or billing purposes.</td><td>A time entry for 8 hours worked on a specific project.</td></tr><tr><td><strong>Vendor Bill</strong></td><td>An invoice received from a supplier for goods or services provided to the company.</td><td>A bill from a supplier for raw materials delivered last month.</td></tr><tr><td><strong>Work Order</strong></td><td>An instruction or authorization to perform work, often related to manufacturing or maintenance tasks.</td><td>A work order to repair a piece of machinery on the production floor.</td></tr></tbody></table><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./build-data-models.html">Data Models</a> — Define Schema Definitions using Common Model entity types</li><li><a href="./build-datahubs.html">Building Data Hubs</a> — Create and configure Data Hubs</li><li><a href="./reference-connectors.html">Connectors Catalog</a> — Supported connector systems</li><li><a href="./datahub-action-mapping.html">Action Mapping</a> — Map endpoint actions to Common Model properties</li></ul>',5)])])}const h=e(a,[["render",d]]);export{p as __pageData,h as default};
